// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title GardenEscrow
 * @dev Gestiona la lógica inmutable de reservas, "escrow virtual" y reputación para GARDEN.
 * Los pagos reales son off-chain (fiat), pero el estado y la reputación son on-chain.
 */
contract GardenEscrow {
    address public immutable owner; // Tú (la plataforma/admin)

    // Estructura de una reserva adaptada al contexto de GARDEN
    struct Booking {
        string bookingId;           // UUID de nuestra base de datos
        string clientId;            // ID del dueño
        string caregiverId;         // ID del cuidador
        uint256 amountBs;           // Monto total en Bs (para transparencia)
        uint256 startTime;          // Timestamp inicio
        uint256 endTime;            // Timestamp fin
        bool isActive;              // True cuando el pago fiat es confirmado (Escrow Virtual)
        bool isCompleted;           // True cuando el servicio finaliza bien
        uint8 rating;               // Calificación 1-5 (0 si no calificado)
        string petName;             // Nombre del peludo
        string serviceType;         // "HOSPEDAJE" o "PASEO"
    }

    // Mapeo: ID de reserva (UUID string) → datos
    mapping(string => Booking) public bookings;
    uint256 public totalBookings;

    // Eventos para el backend
    event BookingCreated(string indexed bookingId, string petName, uint256 amountBs);
    event PaymentConfirmed(string indexed bookingId, uint256 timestamp);
    event ServiceFinalized(string indexed bookingId, uint8 rating, uint256 timestamp);
    event ServiceCancelled(string indexed bookingId, string reason, uint256 timestamp);

    modifier onlyOwner() {
        require(msg.sender == owner, "Solo el administrador de GARDEN puede llamar esta funcion");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    /**
     * @dev Crea una nueva reserva en la blockchain (Escrow Virtual).
     * Se llama desde el backend cuando el administrador confirma el pago fiat.
     */
    function createBooking(
        string calldata _bookingId,
        string calldata _clientId,
        string calldata _caregiverId,
        uint256 _amountBs,
        uint256 _startTime,
        uint256 _endTime,
        string calldata _petName,
        string calldata _serviceType
    ) external onlyOwner {
        require(bookings[_bookingId].startTime == 0, "La reserva ya existe on-chain");

        bookings[_bookingId] = Booking({
            bookingId: _bookingId,
            clientId: _clientId,
            caregiverId: _caregiverId,
            amountBs: _amountBs,
            startTime: _startTime,
            endTime: _endTime,
            isActive: true, // Se activa directamente al confirmarse el pago fiat
            isCompleted: false,
            rating: 0,
            petName: _petName,
            serviceType: _serviceType
        });

        totalBookings++;

        emit BookingCreated(_bookingId, _petName, _amountBs);
        emit PaymentConfirmed(_bookingId, block.timestamp);
    }

    /**
     * @dev Finaliza el servicio y registra la calificación (Reputación Inmutable).
     */
    function finalizeBooking(string calldata _bookingId, uint8 _rating) external onlyOwner {
        Booking storage b = bookings[_bookingId];
        require(b.isActive, "Reserva no activa o ya finalizada");
        require(!b.isCompleted, "Ya esta marcada como completada");
        require(_rating >= 1 && _rating <= 5, "La calificacion debe ser entre 1 y 5");

        b.isCompleted = true;
        b.isActive = false;
        b.rating = _rating;

        emit ServiceFinalized(_bookingId, _rating, block.timestamp);
    }

    /**
     * @dev Cancela la reserva en el historial on-chain.
     */
    function cancelBooking(string calldata _bookingId, string calldata _reason) external onlyOwner {
        Booking storage b = bookings[_bookingId];
        require(b.isActive, "No se puede cancelar una reserva inactiva o finalizada");

        b.isActive = false;

        emit ServiceCancelled(_bookingId, _reason, block.timestamp);
    }

    /**
     * @dev Obtiene info de una reserva (para transparencia en el frontend)
     */
    function getBooking(string calldata _id) external view returns (Booking memory) {
        return bookings[_id];
    }
}

contracts/GardenProfiles.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title GardenProfiles
 * @dev Gestiona el registro inmutable de identidades y perfiles en GARDEN.
 * Almacena el estado de verificación y datos básicos de confianza para dueños y cuidadores.
 */
contract GardenProfiles {
    address public immutable owner;

    enum UserRole { NONE, CLIENT, CAREGIVER }

    struct Profile {
        string userId;          // UUID de la base de datos
        string name;            // Nombre para mostrar
        UserRole role;          // CLIENT o CAREGIVER
        bool isVerified;        // Estado de verificación de identidad
        uint256 joinedAt;       // Timestamp de registro
        string metadataHash;    // Hash IPFS o JSON string con bio/fotos (opcional)
        bool exists;
    }

    struct PetSummary {
        string petName;
        string breed;
        uint256 lastUpdate;
    }

    // Mapeo: ID de usuario (UUID) -> Datos del perfil
    mapping(string => Profile) public profiles;
    // Mapeo: ID de dueño (UUID) -> Lista de mascotas básicas (creativo)
    mapping(string => PetSummary[]) public ownerPets;

    event ProfileSynced(string indexed userId, string name, UserRole role, bool isVerified);
    event VerificationStatusUpdated(string indexed userId, bool isVerified);
    event PetOnChainAdded(string indexed ownerId, string petName);

    modifier onlyOwner() {
        require(msg.sender == owner, "Solo el admin de GARDEN puede ejecutar esto");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    /**
     * @dev Sincroniza un perfil de la base de datos a la blockchain.
     */
    function syncProfile(
        string calldata _userId,
        string calldata _name,
        uint8 _role,
        bool _isVerified,
        string calldata _metadataHash
    ) external onlyOwner {
        profiles[_userId] = Profile({
            userId: _userId,
            name: _name,
            role: UserRole(_role),
            isVerified: _isVerified,
            joinedAt: profiles[_userId].exists ? profiles[_userId].joinedAt : block.timestamp,
            metadataHash: _metadataHash,
            exists: true
        });

        emit ProfileSynced(_userId, _name, UserRole(_role), _isVerified);
    }

    /**
     * @dev Actualiza el estado de verificación por separado (ej. tras validación de CI).
     */
    function updateVerificationStatus(string calldata _userId, bool _status) external onlyOwner {
        require(profiles[_userId].exists, "El perfil no existe en blockchain");
        profiles[_userId].isVerified = _status;
        emit VerificationStatusUpdated(_userId, _status);
    }

    /**
     * @dev Agrega una mascota al perfil del dueño de forma creativa on-chain.
     */
    function addPetToOwner(string calldata _ownerId, string calldata _petName, string calldata _breed) external onlyOwner {
        require(profiles[_ownerId].exists, "El dueno debe tener perfil sincronizado");
        ownerPets[_ownerId].push(PetSummary({
            petName: _petName,
            breed: _breed,
            lastUpdate: block.timestamp
        }));
        emit PetOnChainAdded(_ownerId, _petName);
    }

    /**
     * @dev Consulta si un usuario está verificado (usado por otros contratos o frontend).
     */
    function isUserVerified(string calldata _userId) external view returns (bool) {
        return profiles[_userId].isVerified;
    }

    function getOwnerPetsCount(string calldata _ownerId) external view returns (uint256) {
        return ownerPets[_ownerId].length;
    }
}

